// Get tile at (col, row)
export function getTile(col, row) {
  if (col < 0 || col >= MAP_WIDTH || row < 0 || row >= MAP_HEIGHT) return 0;
  return mapLayer1[row * MAP_WIDTH + col];
}

// Camera follows car: world→screen
export function worldToScreen(worldX, worldY, camX, camY, canvasW, canvasH) {
  return {
    sx: worldX - camX + canvasW / 2,
    sy: worldY - camY + canvasH / 2,
  };
}
